const data = $input.first().json.body || $input.first().json;
const date = data.date || new Date().toISOString().split('T')[0];
const action = data.action || 'daily_report';

let rows = [];
if (action === 'daily_report') {
  rows.push([date, 'DAILY REPORT', '', '']);
  (data.commits || []).forEach(c => rows.push([date, 'commit', c.sha || '', c.message || '']));
  (data.executions || []).forEach(e => rows.push([date, 'workflow', e.workflow_name || '', e.status || '']));
  (data.health || []).forEach(h => rows.push([date, 'health', h.service || '', h.status || '']));
} else {
  rows.push([date, 'ERROR REPORT', `${data.error_count || 0} errors`, '']);
  (data.errors || []).slice(0, 20).forEach(e => rows.push([date, 'error', e.substring(0, 200), '']));
}

return rows.map(r => ({ json: { date: r[0], type: r[1], detail: r[2], extra: r[3] } }));
